
import { doc, setDoc, getDoc, serverTimestamp, increment, query, collection, where, getDocs } from 'firebase/firestore';
import { admin } from './firebase-admin';
import type { UserProfile } from './types';

// This file has been renamed to db-admin.ts to clarify its server-only, admin-privilege nature.
// This change is part of resolving a build issue where server-side modules were leaking into the client bundle.
// All functions here use the Firebase Admin SDK and should only be called from server-side code like Genkit flows or API routes.


export async function findUserByEmail(email: string): Promise<string | null> {
    if (!email) return null;
    const db = admin.db;
    const usersRef = collection(db, 'users');
    const q = query(usersRef, where("email", "==", email));

    const querySnapshot = await getDocs(q);
    if (querySnapshot.empty) {
        return null;
    }

    return querySnapshot.docs[0].id;
}


export async function updateUserProfileAdmin(uid: string, data: Partial<Omit<UserProfile, 'isSubscribed' | 'credits' | 'createdAt' | 'lastLogin'>>) {
  const db = admin.db;
  const userRef = doc(db, 'users', uid);
  const docSnap = await getDoc(userRef);

  if (docSnap.exists()) {
    await setDoc(userRef, {
      ...data,
      lastLogin: serverTimestamp(),
    }, { merge: true });
  } else {
    await setDoc(userRef, {
      ...data,
      isSubscribed: false,
      credits: 1,
      createdAt: serverTimestamp(),
      lastLogin: serverTimestamp(),
    }, { merge: true });
  }
}


export async function checkUserSubscriptionAdmin(uid: string): Promise<UserProfile | null> {
  const db = admin.db;
  const userRef = doc(db, 'users', uid);
  const docSnap = await getDoc(userRef);

  if (docSnap.exists()) {
    const data = docSnap.data();
    return {
        ...data,
        createdAt: data.createdAt?.toDate ? data.createdAt.toDate().toISOString() : new Date().toISOString(),
        lastLogin: data.lastLogin?.toDate ? data.lastLogin.toDate().toISOString() : new Date().toISOString(),
    } as UserProfile;
  } else {
    return null;
  }
}


export async function activateUserSubscriptionAdmin(uid: string) {
    const db = admin.db;
    const userRef = doc(db, 'users', uid);
    const docSnap = await getDoc(userRef);

    if (!docSnap.exists()) {
        throw new Error("User profile does not exist. Cannot activate subscription.");
    }

    await setDoc(userRef, {
        isSubscribed: true,
        credits: increment(15),
    }, { merge: true });
}


export async function decrementUserCreditsAdmin(uid: string) {
    const db = admin.db;
    const userRef = doc(db, 'users', uid);
    const docSnap = await getDoc(userRef);

    if (!docSnap.exists()) {
        throw new Error("User profile does not exist.");
    }

    const currentCredits = docSnap.data().credits || 0;
    if (currentCredits > 0) {
        await setDoc(userRef, {
            credits: increment(-1),
        }, { merge: true });
    } else {
        throw new Error("User has no credits to decrement.");
    }
}
